import{_ as t,o as a,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Random Image API اور Public Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"ur/Other/random-image-api-and-public-gallery.md","filePath":"ur/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),i={name:"ur/Other/random-image-api-and-public-gallery.md"};function o(l,e,s,c,n,p){return a(),d("div",null,[...e[0]||(e[0]=[r(`<h1 id="random-image-api-اور-public-gallery" tabindex="-1">Random Image API اور Public Gallery <a class="header-anchor" href="#random-image-api-اور-public-gallery" aria-label="Permalink to &quot;Random Image API اور Public Gallery&quot;">​</a></h1><p>دونوں features یہاں configure ہوتے ہیں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API selected directories سے ایک random file واپس کرتا ہے۔ یہ site backgrounds، avatar rotation، یا external pages سے random image calls کے لیے useful ہے۔</p><p>enable ہونے کے بعد استعمال کریں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="random-image-api-settings" tabindex="-1">Random Image API Settings <a class="header-anchor" href="#random-image-api-settings" aria-label="Permalink to &quot;Random Image API Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td><code>/random</code> endpoint on یا off کرتا ہے۔ disabled ہو تو access forbidden ہے۔</td></tr><tr><td>Directories</td><td>random API کن directories کو استعمال کر سکتی ہے، یہ limit کرتا ہے۔ یہاں شامل نہ ہونے والی directories API استعمال نہیں کر سکتی۔</td></tr><tr><td>Call demo</td><td>random API links generate کرتا ہے جنہیں آپ directly copy کر سکتے ہیں۔</td></tr></tbody></table><p>آپ multiple directories منتخب کر سکتے ہیں۔ مثلاً اگر صرف <code>/landscape/</code> اور <code>/portrait/</code> allowed ہوں، random API صرف انہی directories اور ان کی subdirectories سے files pick کر سکتی ہے۔</p><h2 id="random-image-api-parameters" tabindex="-1">Random Image API Parameters <a class="header-anchor" href="#random-image-api-parameters" aria-label="Permalink to &quot;Random Image API Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Example</th><th>Purpose</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>random directory specify کرتا ہے۔</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>media type specify کرتا ہے۔ <code>image</code>، <code>video</code>، <code>audio</code>، یا comma-separated combinations استعمال کریں۔</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>image orientation filter کرتا ہے۔ <code>portrait</code>، <code>landscape</code>، یا <code>auto</code> استعمال کریں۔</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>return format۔ empty کا مطلب redirect، <code>url</code> plain text URL دیتا ہے، <code>json</code> JSON دیتا ہے۔</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td><code>type=url</code> کے ساتھ full URL return کرنے کے لیے۔</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>age rating سے filter کرتا ہے۔</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>صرف وہ files return کرتا ہے جن میں یہ tags ہوں۔</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>ان tags والی files exclude کرتا ہے۔</td></tr></tbody></table><h2 id="return-formats" tabindex="-1">Return Formats <a class="header-anchor" href="#return-formats" aria-label="Permalink to &quot;Return Formats&quot;">​</a></h2><p><code>type</code> کے بغیر API directly random file URL پر redirect کرتا ہے۔</p><p><code>type=url</code> کے ساتھ text URL return ہوتا ہے۔</p><p><code>type=json</code> کے ساتھ file information return ہوتی ہے، جس میں file URL، file ID، file name، file type، tags، rating، اور related metadata شامل ہیں۔</p><h2 id="access-rules" tabindex="-1">Access Rules <a class="header-anchor" href="#access-rules" aria-label="Permalink to &quot;Access Rules&quot;">​</a></h2><p>Random Image API public access rules follow کرتی ہے:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Directory restriction</td><td>صرف allowed directories کی files selected ہو سکتی ہیں۔</td></tr><tr><td>Blocklist</td><td>blocklisted files random pool سے excluded ہوتی ہیں۔</td></tr><tr><td>Allowlist mode</td><td>enabled ہو تو صرف public access کے لیے allowed files return ہوتی ہیں۔</td></tr><tr><td>Age rating</td><td>R12، R16، R18، اور ملتا جلتا content current access mode کے مطابق filter ہوتا ہے۔</td></tr></tbody></table><p>filtering کے بعد کوئی file match نہ ہو تو API no matching result return کرتی ہے۔</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API speed بہتر کرنے کے لیے directory candidate pools cache کرتی ہے۔</p><p>files بدلنے کے بعد ImgBed directory cache version update کرتا ہے، اور later requests candidate pool دوبارہ build کرتی ہیں۔ empty directories مختصر وقت کے لیے cache ہوتی ہیں تاکہ repeated queries نہ ہوں۔</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>Public gallery ان directories کے لیے read-only public browsing page دیتی ہے جنہیں آپ visitors کے لیے allow کرتے ہیں۔</p><p>enable ہونے کے بعد visitors کھول سکتے ہیں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="public-gallery-settings" tabindex="-1">Public Gallery Settings <a class="header-anchor" href="#public-gallery-settings" aria-label="Permalink to &quot;Public Gallery Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>public gallery on یا off کرتا ہے۔ disabled ہو تو visitors browse نہیں کر سکتے۔</td></tr><tr><td>Image loading mode</td><td>controls whether previews use original images or thumbnails۔</td></tr><tr><td>Open directories</td><td>visitors کن directories تک access کر سکتے ہیں، یہ set کرتا ہے۔</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th></tr></thead><tbody><tr><td>Original</td><td>visitor page original files directly load کرتا ہے۔</td></tr><tr><td>Thumbnail</td><td>visitor page faster loading کے لیے thumbnails کو prefer کرتا ہے۔</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories فیصلہ کرتی ہیں کہ visitors کیا دیکھ سکتے ہیں۔</p><p>مثال:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Visitors پھر access کر سکتے ہیں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Subdirectories بھی open کی جا سکتی ہیں، جیسے <code>/2026/lucky/</code>۔ جو directories open نہیں، visitors وہاں blocked ہوں گے۔</p><h2 id="public-gallery-features" tabindex="-1">Public Gallery Features <a class="header-anchor" href="#public-gallery-features" aria-label="Permalink to &quot;Public Gallery Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Browse directories</td><td>open directories میں files اور subdirectories دیکھیں۔</td></tr><tr><td>Search</td><td>file name، file ID، یا tags سے search کریں۔</td></tr><tr><td>Type filter</td><td>images، videos، audio، یا other files filter کریں۔</td></tr><tr><td>Tag filter</td><td>selected tags include یا exclude کریں۔</td></tr><tr><td>Orientation filter</td><td>landscape یا portrait images filter کریں۔</td></tr><tr><td>Time filter</td><td>upload time range سے filter کریں۔</td></tr><tr><td>Extension filter</td><td>file extension سے filter کریں۔</td></tr><tr><td>Copy link</td><td>file access links copy کریں۔</td></tr><tr><td>Media preview</td><td>visitor page پر images، videos، اور audio دیکھیں یا play کریں۔</td></tr></tbody></table><h2 id="public-gallery-access-rules" tabindex="-1">Public Gallery Access Rules <a class="header-anchor" href="#public-gallery-access-rules" aria-label="Permalink to &quot;Public Gallery Access Rules&quot;">​</a></h2><p>Public gallery بھی public access rules follow کرتی ہے:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Open directories</td><td>صرف allowed directories دکھائی جاتی ہیں۔</td></tr><tr><td>Access mode</td><td>content current age-rating access mode کے مطابق filter ہوتا ہے۔</td></tr><tr><td>Allowlist mode</td><td>enabled ہو تو صرف public access کے لیے allowed files دکھائی جاتی ہیں۔</td></tr><tr><td>Blocklist</td><td>blocklisted files hidden ہوتی ہیں۔</td></tr></tbody></table>`,43)])])}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
